const config = $('Restore Configuration').item.json;

// Determine which file to restore from
const filePath = config.source === 'gdrive'
  ? '/tmp/shopify-restore-input.json'
  : config.backup_path;

let resourcesArg = '';
if (config.resources && config.resources !== 'all') {
  resourcesArg = ` --resources ${config.resources}`;
}

let flags = '';
if (config.dry_run) flags += ' --dry-run';
if (config.skip_existing) flags += ' --skip-existing';

const scriptPath = $env.SHOPIFY_RESTORE_SCRIPT_PATH || '/opt/shopify-backup/shopify-restore.mjs';
const command = `node ${scriptPath} --file ${filePath}${resourcesArg}${flags}`;

return [{ json: { command, filePath, config } }];

const stdout = $input.first().json.stdout?.trim();
const stderr = $input.first().json.stderr || '';

let result = {};
try { result = JSON.parse(stdout); } catch { result = { raw: stdout }; }

return [{
  json: {
    status: result.success ? 'success' : 'completed_with_errors',
    ...result,
    log_tail: stderr.split('\n').slice(-30).join('\n'),
    timestamp: new Date().toISOString()
  }
}];

const input = $input.first().json;
return [{
  json: {
    status: 'failed',
    error: (input.stderr || input.message || 'Unknown').split('\n').slice(-20).join('\n'),
    timestamp: new Date().toISOString()
  }
}];
